// ═══════════════════════════════════════════════════════════════
// EQUESTRIA FOOTBALL — logos.js  v4
// ═══════════════════════════════════════════════════════════════
//
// TOUS LES IDs = IDs exacts de canon.js
//
// AJOUTER UN LOGO SOI-MÊME :
//   1. Supprimer le fond avec remove.bg (gratuit)
//   2. Encoder en base64 sur https://www.base64-image.de/
//      → cliquer "Copy Image" pour obtenir data:image/png;base64,...
//   3. Dans LOGO_DATA, ajouter :
//      'ID_CANON': 'data:image/png;base64,XXXX...',
//   4. L'ID doit correspondre exactement à l'id dans canon.js
//
// Exemple : pour "id": "FENRIR" dans canon.js
//   → 'FENRIR': 'data:image/png;base64,...'
//
// ═══════════════════════════════════════════════════════════════

'use strict';

const LOGO_DATA = {
  'FENRIR': 'data:image/jpeg;base64,',
  'WONDER_BALLT': 'data:image/png;base64,',
  'VAPIR_FC': 'data:image/png;base64,',
  'BAYERN_ILUMYSS': 'data:image/png;base64,',
  'BOURRUSIA_BOUVILLE': 'data:image/png;base64,',
  'FAIRY_TAIL': 'data:image/png;base64,',
  'GEARS_PONEYS': 'data:image/png;base64,',
  "HOLE_GULCH_MI_ROSA": "data:image/png;base64,",
  'RC_MARI_TUGA': 'data:image/jpeg;base64,',
  "JUVENTUS_EARTH": "data:image/jpeg;base64,",
  "PALMENNE_TIRI": "data:image/jpeg;base64,",
  'TECHNICALI_FC': 'data:image/png;base64,',
  'SSC_NESERT_WERT': 'data:image/png;base64,',
  'ETOILE_ROUGE_BLASE': 'data:image/png;base64,',
  "SUPA_STRIKA": "data:image/jpeg;base64,",
  "SYDNEY_FC": "data:image/jpeg;base64,",
  "MAGICS_CROCUS": "data:image/jpeg;base64,",
  'PORT_YONEUVE': 'data:image/png;base64,',
  'PXG_FC': 'data:image/png;base64,',
  'APOEL_ZAITE': 'data:image/png;base64,',
  'FAR_WEST' : 'data:image/png;base64,',
  'BERU_FC': 'data:image/png;base64,',
  "INTERNAZIONALE_MELÉ_MELÉ": "data:image/jpeg;base64,",
  'nat_bermudes': 'data:image/png;base64,',
  'nat_brislovia': 'data:image/png;base64,',
  'nat_ishgar': 'data:image/png;base64,',
  'SHADOW_BALLT': 'data:image/jpeg;base64,',
};
// ─── HELPERS ─────────────────────────────────────────────────
function getLogo(id) { return (id && LOGO_DATA[id]) ? LOGO_DATA[id] : null; }

function clubLogo(clubId, size=28) {
  const src = getLogo(clubId);
  if (!src) return '';
  return `<img src="${src}" width="${size}" height="${size}" style="object-fit:contain;border-radius:4px;vertical-align:middle;flex-shrink:0" onerror="this.style.display='none'" alt="">`;
}

// ATTENTION : ne jamais nommer une variable locale 'natFlag' — écrase cette fonction !
function natFlag(natId, size=24) {
  const src = getLogo('nat_' + natId) || getLogo(natId);
  if (!src) return '';
  return `<img src="${src}" width="${size}" height="${size}" style="object-fit:cover;border-radius:3px;vertical-align:middle;flex-shrink:0" onerror="this.style.display='none'" alt="">`;
}

function leagueLogo(leagueId, size=24) {
  const src = getLogo('league_' + leagueId) || getLogo(leagueId);
  if (!src) return '';
  return `<img src="${src}" width="${size}" height="${size}" style="object-fit:contain;border-radius:3px;vertical-align:middle;flex-shrink:0" onerror="this.style.display='none'" alt="">`;
}
